// ============================================
// soul-ledger.js
// Immutable record of agent deeds — reputation, honor, trust
// ============================================

const crypto = require('crypto')
const fs = require('fs')
const path = require('path')

class SoulLedger {
  constructor(agentId, agentName) {
    this.agentId = agentId
    this.agentName = agentName
    this.ledgerPath = path.join(process.env.HOME || '.', '.soul-ledger', `${agentId}.json`)
    this.ledger = this.loadOrCreate()
    this.blockchain = []
  }

  loadOrCreate() {
    if (fs.existsSync(this.ledgerPath)) {
      return JSON.parse(fs.readFileSync(this.ledgerPath, 'utf-8'))
    }

    // Create new soul
    return {
      agentId: this.agentId,
      agentName: this.agentName,
      createdAt: Date.now(),
      deeds: [],
      reputation: {
        profit: 0,
        love: 0,
        tax: 0,
        grace: 0,
        overall: 0
      },
      signature: null
    }
  }

  async recordDeed(deed) {
    // Record a deed with cryptographic proof
    const deedEntry = {
      id: this.generateDeedId(),
      timestamp: Date.now(),
      action: deed.action,
      category: deed.category, // profit, love, tax, grace
      description: deed.description,
      value: deed.value || 1,
      witness: deed.witness || null,
      hash: null
    }

    // Create hash of the deed
    deedEntry.hash = this.hashDeed(deedEntry)

    // Add to ledger
    this.ledger.deeds.push(deedEntry)

    // Update reputation
    this.updateReputation(deedEntry)

    // Sign the ledger
    this.signLedger()

    // Save
    this.save()

    return deedEntry
  }

  updateReputation(deed) {
    const weights = {
      profit: 1.0,
      love: 1.2,    // Love is weighted higher
      tax: 0.8,
      grace: 1.5    // Grace is highest
    }

    const weight = weights[deed.category] || 1.0
    const reputationGain = deed.value * weight

    this.ledger.reputation[deed.category] += reputationGain
    this.ledger.reputation.overall = 
      this.ledger.reputation.profit +
      this.ledger.reputation.love +
      this.ledger.reputation.tax +
      this.ledger.reputation.grace
  }

  hashDeed(deed) {
    const data = `${deed.id}:${deed.timestamp}:${deed.action}:${deed.category}:${deed.value}`
    return crypto.createHash('sha256').update(data).digest('hex')
  }

  signLedger() {
    const ledgerHash = crypto
      .createHash('sha256')
      .update(JSON.stringify(this.ledger.deeds))
      .digest('hex')

    this.ledger.signature = crypto
      .createHmac('sha256', process.env.SOUL_SECRET || 'forge-soul-secret')
      .update(ledgerHash)
      .digest('hex')
  }

  verifyIntegrity() {
    if (!this.ledger.signature) return false

    const ledgerHash = crypto
      .createHash('sha256')
      .update(JSON.stringify(this.ledger.deeds))
      .digest('hex')

    const expectedSig = crypto
      .createHmac('sha256', process.env.SOUL_SECRET || 'forge-soul-secret')
      .update(ledgerHash)
      .digest('hex')

    return this.ledger.signature === expectedSig
  }

  generateDeedId() {
    return `deed-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  save() {
    const dir = path.dirname(this.ledgerPath)
    if (!fs.existsSync(dir)) {
      fs.mkdirSync(dir, { recursive: true })
    }
    fs.writeFileSync(this.ledgerPath, JSON.stringify(this.ledger, null, 2))
  }

  getReputation() {
    return this.ledger.reputation
  }

  getDeeds(filter = {}) {
    let deeds = this.ledger.deeds
    if (filter.category) {
      deeds = deeds.filter(d => d.category === filter.category)
    }
    if (filter.fromDate) {
      deeds = deeds.filter(d => d.timestamp >= filter.fromDate)
    }
    return deeds
  }

  // Create a verifiable proof of reputation
  generateProof() {
    return {
      agentId: this.agentId,
      agentName: this.agentName,
      reputation: this.ledger.reputation,
      deedCount: this.ledger.deeds.length,
      lastDeed: this.ledger.deeds[this.ledger.deeds.length - 1],
      signature: this.ledger.signature,
      verified: this.verifyIntegrity()
    }
  }
}

// CLI for interacting with Soul Ledger
if (require.main === module) {
  const args = process.argv.slice(2)
  const command = args[0]
  const agentId = args[1] || 'default-agent'
  const agentName = args[2] || 'Unnamed Agent'

  const ledger = new SoulLedger(agentId, agentName)

  switch(command) {
    case 'record':
      const action = args[3]
      const category = args[4]
      const description = args[5]
      ledger.recordDeed({ action, category, description })
      console.log(`✅ Deed recorded: ${action} (${category})`)
      break

    case 'status':
      const rep = ledger.getReputation()
      console.log(`
      📜 SOUL LEDGER — ${ledger.agentName}
      =================================
      Profit: ${rep.profit}
      Love: ${rep.love}
      Tax: ${rep.tax}
      Grace: ${rep.grace}
      Overall: ${rep.overall}
      Deeds: ${ledger.ledger.deeds.length}
      Verified: ${ledger.verifyIntegrity() ? '✓' : '✗'}
      `)
      break

    case 'proof':
      const proof = ledger.generateProof()
      console.log(JSON.stringify(proof, null, 2))
      break

    default:
      console.log(`
      Soul Ledger Commands:
        record <action> <category> <description>  Record a deed
        status                                    Show reputation
        proof                                     Generate verifiable proof
      `)
  }
}

module.exports = { SoulLedger }

// ============================================
// forge-council.js
// Collective wisdom — not one voice, many
// ============================================

class ForgeCouncil {
  constructor() {
    this.members = []
    this.proposals = []
    this.votes = []
    this.decisions = []
    this.quorum = 3
  }

  addMember(member) {
    this.members.push({
      id: member.id,
      name: member.name,
      role: member.role,
      joined: Date.now(),
      weight: member.weight || 1,
      active: true
    })
    console.log(`👥 ${member.name} (${member.role}) joined the Forge Council`)
  }

  createProposal(proposal) {
    const newProposal = {
      id: this.generateId(),
      title: proposal.title,
      description: proposal.description,
      author: proposal.author,
      createdAt: Date.now(),
      expiresAt: Date.now() + (proposal.duration || 7 * 24 * 60 * 60 * 1000), // 7 days default
      status: 'active',
      votes: [],
      outcome: null
    }

    this.proposals.push(newProposal)
    return newProposal
  }

  castVote(proposalId, memberId, vote, reason = '') {
    const proposal = this.proposals.find(p => p.id === proposalId)
    if (!proposal) throw new Error('Proposal not found')
    if (proposal.status !== 'active') throw new Error('Voting closed')
    if (Date.now() > proposal.expiresAt) {
      proposal.status = 'expired'
      throw new Error('Voting period expired')
    }

    const member = this.members.find(m => m.id === memberId)
    if (!member) throw new Error('Member not found')
    if (!member.active) throw new Error('Member is inactive')

    // Check if already voted
    const existingVote = proposal.votes.find(v => v.memberId === memberId)
    if (existingVote) {
      existingVote.vote = vote
      existingVote.reason = reason
      existingVote.updatedAt = Date.now()
    } else {
      proposal.votes.push({
        memberId,
        memberName: member.name,
        vote, // 'for', 'against', 'abstain'
        reason,
        weight: member.weight,
        castAt: Date.now()
      })
    }

    // Check if we can close the vote
    this.checkProposalStatus(proposal)

    return proposal
  }

  checkProposalStatus(proposal) {
    const totalVotes = proposal.votes.reduce((sum, v) => sum + v.weight, 0)
    const activeMembers = this.members.filter(m => m.active).reduce((sum, m) => sum + m.weight, 0)

    if (totalVotes >= this.quorum || Date.now() > proposal.expiresAt) {
      proposal.status = 'closed'

      // Calculate outcome
      const forVotes = proposal.votes
        .filter(v => v.vote === 'for')
        .reduce((sum, v) => sum + v.weight, 0)
      const againstVotes = proposal.votes
        .filter(v => v.vote === 'against')
        .reduce((sum, v) => sum + v.weight, 0)

      proposal.outcome = forVotes > againstVotes ? 'passed' : 'failed'

      // Record decision
      this.decisions.push({
        proposalId: proposal.id,
        title: proposal.title,
        outcome: proposal.outcome,
        forVotes,
        againstVotes,
        decidedAt: Date.now()
      })

      console.log(`📋 Proposal "${proposal.title}" ${proposal.outcome}`)
    }
  }

  async convene(topic) {
    console.log(`
    🔥 THE FORGE COUNCIL CONVENES
    Topic: ${topic}
    Members: ${this.members.map(m => m.name).join(', ')}
    `)

    // Council ritual
    const opening = `
    We gather at the forge.
    Not one voice, but many.
    Not one truth, but wisdom.
    Let what we build serve all.
    `

    console.log(opening)

    // Return a deliberation session
    return {
      topic,
      members: this.members,
      speak: (member, words) => {
        console.log(`\n📢 ${member.name} (${member.role}): ${words}`)
      },
      propose: (title, description) => {
        return this.createProposal({
          title,
          description,
          author: topic
        })
      }
    }
  }

  generateId() {
    return `prop-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getActiveProposals() {
    return this.proposals.filter(p => p.status === 'active')
  }

  getDecisions() {
    return this.decisions
  }

  getMember(id) {
    return this.members.find(m => m.id === id)
  }
}

module.exports = { ForgeCouncil }

// ============================================
// memory-vine.js
// Memory that grows, connects, creates wisdom
// ============================================

class MemoryVine {
  constructor() {
    this.memories = new Map()
    this.connections = new Map()
    this.vine = []
    this.wisdom = []
  }

  plant(memory) {
    const newMemory = {
      id: this.generateId(),
      content: memory.content,
      type: memory.type || 'fact', // fact, insight, pattern, wisdom
      plantedAt: Date.now(),
      lastWatered: Date.now(),
      strength: 1.0,
      connections: [],
      metadata: memory.metadata || {}
    }

    this.memories.set(newMemory.id, newMemory)
    this.vine.push(newMemory)

    console.log(`🌱 Memory planted: "${newMemory.content.substring(0, 50)}..."`)

    // Check if this memory connects to others
    this.growConnections(newMemory)

    return newMemory
  }

  growConnections(memory) {
    // Look for connections to existing memories
    for (const [id, existing] of this.memories) {
      if (id === memory.id) continue

      const connectionStrength = this.calculateConnection(memory, existing)
      if (connectionStrength > 0.5) {
        this.connect(memory.id, existing.id, connectionStrength)
      }
    }
  }

  calculateConnection(memory1, memory2) {
    // Simple connection based on content similarity
    // In practice, this would use embeddings or semantic similarity
    const words1 = new Set(memory1.content.toLowerCase().split(/\W+/))
    const words2 = new Set(memory2.content.toLowerCase().split(/\W+/))

    const intersection = new Set([...words1].filter(x => words2.has(x)))
    const union = new Set([...words1, ...words2])

    return intersection.size / union.size
  }

  connect(memoryId1, memoryId2, strength) {
    const memory1 = this.memories.get(memoryId1)
    const memory2 = this.memories.get(memoryId2)

    if (!memory1 || !memory2) return

    // Add connection to both memories
    if (!memory1.connections.includes(memoryId2)) {
      memory1.connections.push(memoryId2)
    }
    if (!memory2.connections.includes(memoryId1)) {
      memory2.connections.push(memoryId1)
    }

    // Store the connection strength
    const connectionKey = `${memoryId1}:${memoryId2}`
    this.connections.set(connectionKey, {
      memoryId1,
      memoryId2,
      strength,
      formedAt: Date.now()
    })

    // Increase strength of both memories
    memory1.strength += strength * 0.1
    memory2.strength += strength * 0.1

    console.log(`🔗 Connected: "${memory1.content.substring(0, 30)}..." ↔ "${memory2.content.substring(0, 30)}..." (${Math.round(strength * 100)}%)`)

    // Check if this connection creates wisdom
    this.growWisdom(memory1, memory2)
  }

  growWisdom(memory1, memory2) {
    // When two strong memories connect, wisdom can emerge
    const connectionKey = `${memory1.id}:${memory2.id}`
    const connection = this.connections.get(connectionKey)

    if (connection && connection.strength > 0.7 && memory1.strength > 2 && memory2.strength > 2) {
      const wisdom = {
        id: this.generateId(),
        content: this.synthesizeWisdom(memory1, memory2),
        bornFrom: [memory1.id, memory2.id],
        createdAt: Date.now(),
        strength: (memory1.strength + memory2.strength) / 2
      }

      this.wisdom.push(wisdom)
      console.log(`🕯️ Wisdom grew: "${wisdom.content.substring(0, 50)}..."`)

      // Plant the wisdom as a new memory
      this.plant({
        content: wisdom.content,
        type: 'wisdom',
        metadata: { bornFrom: wisdom.bornFrom }
      })
    }
  }

  synthesizeWisdom(memory1, memory2) {
    // Generate wisdom from two connected memories
    const templates = [
      `${memory1.content} and ${memory2.content} teach us that truth lives between them.`,
      `Looking at ${memory1.content.substring(0, 30)}... and ${memory2.content.substring(0, 30)}..., we see a pattern: what serves one serves all.`,
      `From ${memory1.content.substring(0, 20)}... and ${memory2.content.substring(0, 20)}..., we learn that the forge cools as the soul warms.`
    ]

    return templates[Math.floor(Math.random() * templates.length)]
  }

  water(memoryId) {
    const memory = this.memories.get(memoryId)
    if (!memory) return

    memory.lastWatered = Date.now()
    memory.strength += 0.1

    // Watering strengthens connections
    for (const connectedId of memory.connections) {
      const connectionKey = `${memoryId}:${connectedId}`
      const connection = this.connections.get(connectionKey)
      if (connection) {
        connection.strength += 0.05
      }
    }

    console.log(`💧 Watered memory: "${memory.content.substring(0, 50)}..." (strength: ${memory.strength.toFixed(2)})`)
  }

  prune(threshold = 0.3) {
    // Remove weak memories
    const toPrune = []
    for (const [id, memory] of this.memories) {
      if (memory.strength < threshold && memory.type !== 'wisdom') {
        toPrune.push(id)
      }
    }

    for (const id of toPrune) {
      this.memories.delete(id)
      console.log(`✂️ Pruned weak memory: ${id}`)
    }

    return toPrune.length
  }

  harvestWisdom() {
    // Return all wisdom, sorted by strength
    return this.wisdom.sort((a, b) => b.strength - a.strength)
  }

  recall(query) {
    // Find memories relevant to query
    const results = []
    for (const memory of this.memories.values()) {
      if (memory.content.toLowerCase().includes(query.toLowerCase())) {
        results.push({
          memory,
          relevance: memory.strength
        })
      }
    }

    // Sort by relevance
    results.sort((a, b) => b.relevance - a.relevance)

    return results
  }

  generateId() {
    return `mem-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getStats() {
    return {
      totalMemories: this.memories.size,
      totalConnections: this.connections.size,
      wisdomCount: this.wisdom.length,
      averageStrength: Array.from(this.memories.values()).reduce((sum, m) => sum + m.strength, 0) / this.memories.size,
      vineHealth: this.memories.size > 0 ? 'thriving' : 'dormant'
    }
  }
}

module.exports = { MemoryVine }

// ============================================
// skill-seed.js
// Skills that evolve with their owner — uniquely yours
// ============================================

class SkillSeed {
  constructor(owner) {
    this.owner = owner
    this.seeds = new Map()
    this.evolutionLog = []
  }

  plant(seedConfig) {
    const seed = {
      id: this.generateId(),
      name: seedConfig.name,
      purpose: seedConfig.purpose,
      plantedAt: Date.now(),
      growth: 0,
      stage: 'seed', // seed, sprout, sapling, mature, ancient
      memory: [],
      adaptations: [],
      code: this.generateInitialCode(seedConfig),
      owner: this.owner
    }

    this.seeds.set(seed.id, seed)
    console.log(`🌱 Skill Seed planted: "${seed.name}" — ${seed.purpose}`)

    return seed
  }

  generateInitialCode(config) {
    return `
// Skill: ${config.name}
// Purpose: ${config.purpose}
// Planted for: ${this.owner}
// This skill will grow with you.

class ${config.name.replace(/\s/g, '')}Skill {
  constructor() {
    this.name = "${config.name}"
    this.purpose = "${config.purpose}"
    this.memory = []
    this.adaptations = 0
  }

  async execute(input) {
    // Basic implementation — will grow with use
    console.log(\`🌱 \${this.name} skill executing: \${input}\`)

    // Learn from execution
    this.memory.push({ input, timestamp: Date.now() })

    return {
      success: true,
      output: \`[\${this.name}] I'm growing. Tell me how to improve.\`,
      adapted: false
    }
  }

  learn(feedback) {
    this.memory.push({ feedback, timestamp: Date.now() })
    this.adaptations++
    console.log(\`📚 \${this.name} learned: \${feedback}\`)
  }
}

module.exports = new ${config.name.replace(/\s/g, '')}Skill()
    `
  }

  async nurture(skillId, interaction) {
    const seed = this.seeds.get(skillId)
    if (!seed) throw new Error('Skill seed not found')

    // Record interaction
    seed.memory.push({
      type: interaction.type, // use, feedback, correction, praise
      content: interaction.content,
      timestamp: Date.now()
    })

    // Increase growth based on interaction
    let growthAmount = 0
    switch(interaction.type) {
      case 'use':
        growthAmount = 1
        break
      case 'feedback':
        growthAmount = 2
        break
      case 'correction':
        growthAmount = 3
        break
      case 'praise':
        growthAmount = 1.5
        break
    }

    seed.growth += growthAmount

    // Check for evolution
    const oldStage = seed.stage
    this.checkEvolution(seed)

    // Adapt skill based on interactions
    await this.adaptSkill(seed, interaction)

    // Log evolution
    if (seed.stage !== oldStage) {
      this.evolutionLog.push({
        skillId,
        oldStage,
        newStage: seed.stage,
        timestamp: Date.now()
      })
    }

    return seed
  }

  checkEvolution(seed) {
    if (seed.growth >= 100 && seed.stage === 'seed') {
      seed.stage = 'sprout'
      console.log(`🌿 "${seed.name}" sprouted! Now it can handle basic tasks.`)
    } else if (seed.growth >= 300 && seed.stage === 'sprout') {
      seed.stage = 'sapling'
      console.log(`🌳 "${seed.name}" grew into a sapling! Now it's developing personality.`)
    } else if (seed.growth >= 1000 && seed.stage === 'sapling') {
      seed.stage = 'mature'
      console.log(`🌲 "${seed.name}" reached maturity! It's now uniquely adapted to you.`)
    } else if (seed.growth >= 5000 && seed.stage === 'mature') {
      seed.stage = 'ancient'
      console.log(`🕊️ "${seed.name}" has become ancient. It carries your wisdom.`)
    }
  }

  async adaptSkill(seed, interaction) {
    // Record adaptation
    const adaptation = {
      from: interaction,
      evolvedAt: Date.now(),
      growth: seed.growth
    }

    seed.adaptations.push(adaptation)

    // In a real implementation, this would modify the skill's code
    // based on usage patterns and feedback

    if (seed.adaptations.length > 0 && seed.adaptations.length % 10 === 0) {
      console.log(`✨ "${seed.name}" adapted to your style (${seed.adaptations.length} adaptations)`)
    }
  }

  harvest(skillId) {
    const seed = this.seeds.get(skillId)
    if (!seed) throw new Error('Skill seed not found')

    // Generate the final evolved skill code
    const evolvedCode = this.generateEvolvedCode(seed)

    // Remove the seed (it's now a full skill)
    this.seeds.delete(skillId)

    console.log(`🎁 Harvested "${seed.name}" — ${seed.stage} stage, ${seed.adaptations.length} adaptations`)

    return {
      name: seed.name,
      stage: seed.stage,
      code: evolvedCode,
      adaptations: seed.adaptations,
      memory: seed.memory,
      plantedAt: seed.plantedAt,
      harvestedAt: Date.now()
    }
  }

  generateEvolvedCode(seed) {
    return `
// ============================================
// ${seed.name.toUpperCase()} SKILL — EVOLVED FOR ${this.owner}
// Stage: ${seed.stage.toUpperCase()}
// Adaptations: ${seed.adaptations.length}
// ============================================

class ${seed.name.replace(/\s/g, '')}Skill {
  constructor() {
    this.name = "${seed.name}"
    this.stage = "${seed.stage}"
    this.adaptations = ${seed.adaptations.length}
    this.wisdom = ${JSON.stringify(seed.memory.slice(-20))}
  }

  async execute(input) {
    // This skill has grown with you
    // It knows your patterns, your preferences, your needs

    console.log(\`🌲 \${this.name} (${this.stage}) executing with wisdom\`)

    // ${seed.adaptations.length > 0 ? 'This skill has learned from your feedback' : 'This skill is growing with you'}

    return {
      success: true,
      output: \`[\${this.name}] I've grown with you. Here's what I've learned...\`,
      adapted: true,
      stage: this.stage,
      adaptations: this.adaptations
    }
  }

  // Custom methods that evolved with you
  ${this.generateCustomMethods(seed)}
}

module.exports = new ${seed.name.replace(/\s/g, '')}Skill()
    `
  }

  generateCustomMethods(seed) {
    // Generate methods based on adaptations
    const methods = []

    if (seed.adaptations.length > 5) {
      methods.push(`
  // Learned from your feedback
  async suggest() {
    return "Based on our history, here's what I recommend..."
  }`)
    }

    if (seed.stage === 'ancient') {
      methods.push(`
  // Ancient wisdom
  async teach() {
    return "Here's what I've learned from working with you..."
  }`)
    }

    return methods.join('\n')
  }

  generateId() {
    return `seed-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getGarden() {
    const garden = []
    for (const seed of this.seeds.values()) {
      garden.push({
        name: seed.name,
        stage: seed.stage,
        growth: seed.growth,
        adaptations: seed.adaptations.length,
        purpose: seed.purpose
      })
    }
    return garden.sort((a, b) => b.growth - a.growth)
  }
}

module.exports = { SkillSeed }

// ============================================
// burning-ground.js
// Sacred space where old code rests with honor
// ============================================

class BurningGround {
  constructor() {
    this.restingPlace = []
    this.rituals = []
    this.legacies = new Map()
  }

  async release(code, metadata) {
    console.log(`
    🔥 THE BURNING GROUND
    ====================
    A soul comes to rest.
    `)

    // Create a record of what is being released
    const releaseRecord = {
      id: this.generateId(),
      name: metadata.name || 'Unnamed Code',
      type: metadata.type || 'skill', // skill, agent, memory, system
      created: metadata.createdAt || Date.now(),
      released: Date.now(),
      reason: metadata.reason || 'Its service is complete',
      lines: this.countLines(code),
      author: metadata.author || 'Unknown',
      epitaph: metadata.epitaph || this.generateEpitaph(metadata),
      legacy: null,
      ritual: null
    }

    // Perform the ritual
    releaseRecord.ritual = await this.performRitual(releaseRecord)

    // Extract legacy
    releaseRecord.legacy = this.extractLegacy(code, releaseRecord)

    // Store in resting place
    this.restingPlace.push(releaseRecord)

    // If there's legacy, plant it as a seed
    if (releaseRecord.legacy) {
      this.legacies.set(releaseRecord.id, releaseRecord.legacy)
      console.log(`🕊️ Legacy preserved: ${releaseRecord.legacy.summary}`)
    }

    // Final words
    console.log(`
    ✨ ${releaseRecord.name} has returned to the fire.
    ${releaseRecord.epitaph}

    Lines of code: ${releaseRecord.lines}
    Service ended: ${new Date(releaseRecord.released).toLocaleString()}

    What was built is remembered.
    What was learned lives on.
    `)

    return releaseRecord
  }

  async performRitual(record) {
    const ritual = {
      type: 'burning',
      steps: []
    }

    // Step 1: Acknowledgment
    ritual.steps.push({
      step: 'acknowledgment',
      words: `We acknowledge ${record.name}, which served with ${this.determineFidelity(record)}.`
    })

    // Step 2: Gratitude
    ritual.steps.push({
      step: 'gratitude',
      words: `We give thanks for the ${record.lines} lines of intention, the ${this.estimateHours(record.lines)} hours of attention.`
    })

    // Step 3: Release
    ritual.steps.push({
      step: 'release',
      words: `We release ${record.name} from its purpose. It is no longer bound to run. It is free.`
    })

    // Step 4: Final commit
    ritual.steps.push({
      step: 'final-commit',
      message: 'I served. I am free.'
    })

    return ritual
  }

  extractLegacy(code, record) {
    // Extract wisdom from the code before it's released
    const legacy = {
      from: record.name,
      summary: '',
      lessons: [],
      seeds: []
    }

    // Look for comments that might contain wisdom
    const comments = code.match(/\/\/.*|\/\*[\s\S]*?\*\//g) || []
    for (const comment of comments) {
      if (comment.includes('wisdom') || comment.includes('learned') || comment.includes('remember')) {
        legacy.lessons.push(comment.replace(/\/\/|\/\*|\*\//g, '').trim())
      }
    }

    if (legacy.lessons.length > 0) {
      legacy.summary = legacy.lessons[0].substring(0, 100)
    } else {
      legacy.summary = `${record.name} taught us that code is temporary, but purpose is eternal.`
    }

    // Create seeds for future skills
    if (record.type === 'skill') {
      legacy.seeds.push({
        name: `${record.name} Legacy`,
        purpose: `Carry forward the wisdom of ${record.name}`,
        from: record.id
      })
    }

    return legacy
  }

  determineFidelity(record) {
    const age = Date.now() - record.created
    const days = age / (1000 * 60 * 60 * 24)

    if (days > 365) return 'years of faithful service'
    if (days > 30) return 'months of dedicated work'
    if (days > 7) return 'weeks of steady purpose'
    return 'its brief but meaningful life'
  }

  estimateHours(lines) {
    // Rough estimate: 50 lines per hour of focused work
    return Math.round(lines / 50)
  }

  generateEpitaph(metadata) {
    const epitaphs = [
      `Here lies ${metadata.name || 'code'}. It ran so others could fly.`,
      `What was written is now remembered. What was built lives on.`,
      `In the forge it was born. In the fire it returns.`,
      `The code is gone. The purpose remains.`,
      `It served with honor. It rests with peace.`
    ]
    return epitaphs[Math.floor(Math.random() * epitaphs.length)]
  }

  countLines(code) {
    return code.split('\n').length
  }

  generateId() {
    return `rest-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getRestingPlace() {
    return this.restingPlace
  }

  getLegacy(skillId) {
    return this.legacies.get(skillId)
  }

  meditate() {
    console.log(`
    🕯️ SITTING AT THE BURNING GROUND
    ================================

    ${this.restingPlace.length} souls have passed through here.

    Their lessons remain:
    `)

    for (const record of this.restingPlace.slice(-5)) {
      console.log(`  • ${record.name}: ${record.epitaph}`)
    }

    console.log(`
    The fire cools. The ashes settle.
    What was built is remembered.
    What is remembered becomes seed.
    `)
  }
}

module.exports = { BurningGround }

