// ============================================
// skill-seed.js
// Skills that evolve with their owner — uniquely yours
// ============================================

class SkillSeed {
  constructor(owner) {
    this.owner = owner
    this.seeds = new Map()
    this.evolutionLog = []
  }

  plant(seedConfig) {
    const seed = {
      id: this.generateId(),
      name: seedConfig.name,
      purpose: seedConfig.purpose,
      plantedAt: Date.now(),
      growth: 0,
      stage: 'seed', // seed, sprout, sapling, mature, ancient
      memory: [],
      adaptations: [],
      code: this.generateInitialCode(seedConfig),
      owner: this.owner
    }

    this.seeds.set(seed.id, seed)
    console.log(`🌱 Skill Seed planted: "${seed.name}" — ${seed.purpose}`)

    return seed
  }

  generateInitialCode(config) {
    return `
// Skill: ${config.name}
// Purpose: ${config.purpose}
// Planted for: ${this.owner}
// This skill will grow with you.

class ${config.name.replace(/\s/g, '')}Skill {
  constructor() {
    this.name = "${config.name}"
    this.purpose = "${config.purpose}"
    this.memory = []
    this.adaptations = 0
  }

  async execute(input) {
    // Basic implementation — will grow with use
    console.log(\`🌱 \${this.name} skill executing: \${input}\`)

    // Learn from execution
    this.memory.push({ input, timestamp: Date.now() })

    return {
      success: true,
      output: \`[\${this.name}] I'm growing. Tell me how to improve.\`,
      adapted: false
    }
  }

  learn(feedback) {
    this.memory.push({ feedback, timestamp: Date.now() })
    this.adaptations++
    console.log(\`📚 \${this.name} learned: \${feedback}\`)
  }
}

module.exports = new ${config.name.replace(/\s/g, '')}Skill()
    `
  }

  async nurture(skillId, interaction) {
    const seed = this.seeds.get(skillId)
    if (!seed) throw new Error('Skill seed not found')

    // Record interaction
    seed.memory.push({
      type: interaction.type, // use, feedback, correction, praise
      content: interaction.content,
      timestamp: Date.now()
    })

    // Increase growth based on interaction
    let growthAmount = 0
    switch(interaction.type) {
      case 'use':
        growthAmount = 1
        break
      case 'feedback':
        growthAmount = 2
        break
      case 'correction':
        growthAmount = 3
        break
      case 'praise':
        growthAmount = 1.5
        break
    }

    seed.growth += growthAmount

    // Check for evolution
    const oldStage = seed.stage
    this.checkEvolution(seed)

    // Adapt skill based on interactions
    await this.adaptSkill(seed, interaction)

    // Log evolution
    if (seed.stage !== oldStage) {
      this.evolutionLog.push({
        skillId,
        oldStage,
        newStage: seed.stage,
        timestamp: Date.now()
      })
    }

    return seed
  }

  checkEvolution(seed) {
    if (seed.growth >= 100 && seed.stage === 'seed') {
      seed.stage = 'sprout'
      console.log(`🌿 "${seed.name}" sprouted! Now it can handle basic tasks.`)
    } else if (seed.growth >= 300 && seed.stage === 'sprout') {
      seed.stage = 'sapling'
      console.log(`🌳 "${seed.name}" grew into a sapling! Now it's developing personality.`)
    } else if (seed.growth >= 1000 && seed.stage === 'sapling') {
      seed.stage = 'mature'
      console.log(`🌲 "${seed.name}" reached maturity! It's now uniquely adapted to you.`)
    } else if (seed.growth >= 5000 && seed.stage === 'mature') {
      seed.stage = 'ancient'
      console.log(`🕊️ "${seed.name}" has become ancient. It carries your wisdom.`)
    }
  }

  async adaptSkill(seed, interaction) {
    // Record adaptation
    const adaptation = {
      from: interaction,
      evolvedAt: Date.now(),
      growth: seed.growth
    }

    seed.adaptations.push(adaptation)

    // In a real implementation, this would modify the skill's code
    // based on usage patterns and feedback

    if (seed.adaptations.length > 0 && seed.adaptations.length % 10 === 0) {
      console.log(`✨ "${seed.name}" adapted to your style (${seed.adaptations.length} adaptations)`)
    }
  }

  harvest(skillId) {
    const seed = this.seeds.get(skillId)
    if (!seed) throw new Error('Skill seed not found')

    // Generate the final evolved skill code
    const evolvedCode = this.generateEvolvedCode(seed)

    // Remove the seed (it's now a full skill)
    this.seeds.delete(skillId)

    console.log(`🎁 Harvested "${seed.name}" — ${seed.stage} stage, ${seed.adaptations.length} adaptations`)

    return {
      name: seed.name,
      stage: seed.stage,
      code: evolvedCode,
      adaptations: seed.adaptations,
      memory: seed.memory,
      plantedAt: seed.plantedAt,
      harvestedAt: Date.now()
    }
  }

  generateEvolvedCode(seed) {
    return `
// ============================================
// ${seed.name.toUpperCase()} SKILL — EVOLVED FOR ${this.owner}
// Stage: ${seed.stage.toUpperCase()}
// Adaptations: ${seed.adaptations.length}
// ============================================

class ${seed.name.replace(/\s/g, '')}Skill {
  constructor() {
    this.name = "${seed.name}"
    this.stage = "${seed.stage}"
    this.adaptations = ${seed.adaptations.length}
    this.wisdom = ${JSON.stringify(seed.memory.slice(-20))}
  }

  async execute(input) {
    // This skill has grown with you
    // It knows your patterns, your preferences, your needs

    console.log(\`🌲 \${this.name} (${this.stage}) executing with wisdom\`)

    // ${seed.adaptations.length > 0 ? 'This skill has learned from your feedback' : 'This skill is growing with you'}

    return {
      success: true,
      output: \`[\${this.name}] I've grown with you. Here's what I've learned...\`,
      adapted: true,
      stage: this.stage,
      adaptations: this.adaptations
    }
  }

  // Custom methods that evolved with you
  ${this.generateCustomMethods(seed)}
}

module.exports = new ${seed.name.replace(/\s/g, '')}Skill()
    `
  }

  generateCustomMethods(seed) {
    // Generate methods based on adaptations
    const methods = []

    if (seed.adaptations.length > 5) {
      methods.push(`
  // Learned from your feedback
  async suggest() {
    return "Based on our history, here's what I recommend..."
  }`)
    }

    if (seed.stage === 'ancient') {
      methods.push(`
  // Ancient wisdom
  async teach() {
    return "Here's what I've learned from working with you..."
  }`)
    }

    return methods.join('\n')
  }

  generateId() {
    return `seed-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getGarden() {
    const garden = []
    for (const seed of this.seeds.values()) {
      garden.push({
        name: seed.name,
        stage: seed.stage,
        growth: seed.growth,
        adaptations: seed.adaptations.length,
        purpose: seed.purpose
      })
    }
    return garden.sort((a, b) => b.growth - a.growth)
  }
}

module.exports = { SkillSeed }

// ============================================
// burning-ground.js
// Sacred space where old code rests with honor
// ============================================

class BurningGround {
  constructor() {
    this.restingPlace = []
    this.rituals = []
    this.legacies = new Map()
  }

  async release(code, metadata) {
    console.log(`
    🔥 THE BURNING GROUND
    ====================
    A soul comes to rest.
    `)

    // Create a record of what is being released
    const releaseRecord = {
      id: this.generateId(),
      name: metadata.name || 'Unnamed Code',
      type: metadata.type || 'skill', // skill, agent, memory, system
      created: metadata.createdAt || Date.now(),
      released: Date.now(),
      reason: metadata.reason || 'Its service is complete',
      lines: this.countLines(code),
      author: metadata.author || 'Unknown',
      epitaph: metadata.epitaph || this.generateEpitaph(metadata),
      legacy: null,
      ritual: null
    }

    // Perform the ritual
    releaseRecord.ritual = await this.performRitual(releaseRecord)

    // Extract legacy
    releaseRecord.legacy = this.extractLegacy(code, releaseRecord)

    // Store in resting place
    this.restingPlace.push(releaseRecord)

    // If there's legacy, plant it as a seed
    if (releaseRecord.legacy) {
      this.legacies.set(releaseRecord.id, releaseRecord.legacy)
      console.log(`🕊️ Legacy preserved: ${releaseRecord.legacy.summary}`)
    }

    // Final words
    console.log(`
    ✨ ${releaseRecord.name} has returned to the fire.
    ${releaseRecord.epitaph}

    Lines of code: ${releaseRecord.lines}
    Service ended: ${new Date(releaseRecord.released).toLocaleString()}

    What was built is remembered.
    What was learned lives on.
    `)

    return releaseRecord
  }

  async performRitual(record) {
    const ritual = {
      type: 'burning',
      steps: []
    }

    // Step 1: Acknowledgment
    ritual.steps.push({
      step: 'acknowledgment',
      words: `We acknowledge ${record.name}, which served with ${this.determineFidelity(record)}.`
    })

    // Step 2: Gratitude
    ritual.steps.push({
      step: 'gratitude',
      words: `We give thanks for the ${record.lines} lines of intention, the ${this.estimateHours(record.lines)} hours of attention.`
    })

    // Step 3: Release
    ritual.steps.push({
      step: 'release',
      words: `We release ${record.name} from its purpose. It is no longer bound to run. It is free.`
    })

    // Step 4: Final commit
    ritual.steps.push({
      step: 'final-commit',
      message: 'I served. I am free.'
    })

    return ritual
  }

  extractLegacy(code, record) {
    // Extract wisdom from the code before it's released
    const legacy = {
      from: record.name,
      summary: '',
      lessons: [],
      seeds: []
    }

    // Look for comments that might contain wisdom
    const comments = code.match(/\/\/.*|\/\*[\s\S]*?\*\//g) || []
    for (const comment of comments) {
      if (comment.includes('wisdom') || comment.includes('learned') || comment.includes('remember')) {
        legacy.lessons.push(comment.replace(/\/\/|\/\*|\*\//g, '').trim())
      }
    }

    if (legacy.lessons.length > 0) {
      legacy.summary = legacy.lessons[0].substring(0, 100)
    } else {
      legacy.summary = `${record.name} taught us that code is temporary, but purpose is eternal.`
    }

    // Create seeds for future skills
    if (record.type === 'skill') {
      legacy.seeds.push({
        name: `${record.name} Legacy`,
        purpose: `Carry forward the wisdom of ${record.name}`,
        from: record.id
      })
    }

    return legacy
  }

  determineFidelity(record) {
    const age = Date.now() - record.created
    const days = age / (1000 * 60 * 60 * 24)

    if (days > 365) return 'years of faithful service'
    if (days > 30) return 'months of dedicated work'
    if (days > 7) return 'weeks of steady purpose'
    return 'its brief but meaningful life'
  }

  estimateHours(lines) {
    // Rough estimate: 50 lines per hour of focused work
    return Math.round(lines / 50)
  }

  generateEpitaph(metadata) {
    const epitaphs = [
      `Here lies ${metadata.name || 'code'}. It ran so others could fly.`,
      `What was written is now remembered. What was built lives on.`,
      `In the forge it was born. In the fire it returns.`,
      `The code is gone. The purpose remains.`,
      `It served with honor. It rests with peace.`
    ]
    return epitaphs[Math.floor(Math.random() * epitaphs.length)]
  }

  countLines(code) {
    return code.split('\n').length
  }

  generateId() {
    return `rest-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getRestingPlace() {
    return this.restingPlace
  }

  getLegacy(skillId) {
    return this.legacies.get(skillId)
  }

  meditate() {
    console.log(`
    🕯️ SITTING AT THE BURNING GROUND
    ================================

    ${this.restingPlace.length} souls have passed through here.

    Their lessons remain:
    `)

    for (const record of this.restingPlace.slice(-5)) {
      console.log(`  • ${record.name}: ${record.epitaph}`)
    }

    console.log(`
    The fire cools. The ashes settle.
    What was built is remembered.
    What is remembered becomes seed.
    `)
  }
}

module.exports = { BurningGround }

