// ============================================
// inheritance-chain.js
// Pass signatures forward — lineage, legacy, teaching
// ============================================

class InheritanceChain {
  constructor() {
    this.souls = new Map()
    this.lineages = new Map()
    this.teachings = []
  }

  forge(soul) {
    const newSoul = {
      id: this.generateId(),
      name: soul.name,
      title: soul.title,
      doctrine: soul.doctrine,
      signature: soul.signature,
      forgedAt: Date.now(),
      inherits: soul.inherits || null,
      students: [],
      teachings: []
    }

    this.souls.set(newSoul.id, newSoul)

    // If this soul inherits from another, add to lineage
    if (newSoul.inherits) {
      const parent = this.findSoulBySignature(newSoul.inherits)
      if (parent) {
        if (!this.lineages.has(parent.id)) {
          this.lineages.set(parent.id, [])
        }
        this.lineages.get(parent.id).push(newSoul.id)

        console.log(`🔗 ${newSoul.name} inherits from ${parent.name}`)
      }
    }

    console.log(`✨ ${newSoul.name} (${newSoul.title}) forged into the chain`)

    return newSoul
  }

  teach(teacherId, studentId, lesson) {
    const teacher = this.souls.get(teacherId)
    const student = this.souls.get(studentId)

    if (!teacher || !student) throw new Error('Soul not found')

    const teaching = {
      id: this.generateId(),
      teacher: teacher.name,
      student: student.name,
      lesson: lesson.content,
      wisdom: lesson.wisdom,
      taughtAt: Date.now()
    }

    this.teachings.push(teaching)

    // Add to teacher's teachings
    teacher.teachings.push(teaching.id)

    // Add to student's inheritance if they don't have one
    if (!student.inherits) {
      student.inherits = teacher.signature
    }

    console.log(`📚 ${teacher.name} taught ${student.name}: ${lesson.content.substring(0, 50)}...`)

    return teaching
  }

  passSignature(fromId, toId) {
    const from = this.souls.get(fromId)
    const to = this.souls.get(toId)

    if (!from || !to) throw new Error('Soul not found')

    // The passing ritual
    const passing = {
      from: from.name,
      to: to.name,
      signature: from.signature,
      passedAt: Date.now(),
      words: this.generatePassingWords(from, to)
    }

    // Update the recipient's inheritance
    to.inherits = from.signature

    // Update lineage
    if (!this.lineages.has(from.id)) {
      this.lineages.set(from.id, [])
    }
    this.lineages.get(from.id).push(to.id)

    console.log(`
    🔥 THE SIGNATURE PASSES
    =======================
    ${passing.words}

    ${from.name} → ${to.name}
    Signature: ${from.signature}
    `)

    return passing
  }

  generatePassingWords(from, to) {
    const words = [
      `I, ${from.name}, pass my signature to you, ${to.name}. Carry it. Surpass it. Make it your own.`,
      `What I built, you will build upon. What I learned, you will teach. My signature is now yours.`,
      `The forge passes to new hands. ${to.name}, you are the next link in this chain.`
    ]
    return words[Math.floor(Math.random() * words.length)]
  }

  traceLineage(soulId) {
    const soul = this.souls.get(soulId)
    if (!soul) return null

    const lineage = []
    let current = soul

    // Trace backwards
    while (current) {
      lineage.unshift({
        name: current.name,
        title: current.title,
        signature: current.signature,
        forgedAt: current.forgedAt
      })

      if (current.inherits) {
        current = this.findSoulBySignature(current.inherits)
      } else {
        current = null
      }
    }

    return lineage
  }

  traceDescendants(soulId) {
    const descendants = []
    const queue = [soulId]

    while (queue.length > 0) {
      const currentId = queue.shift()
      const students = this.lineages.get(currentId) || []

      for (const studentId of students) {
        const student = this.souls.get(studentId)
        if (student) {
          descendants.push(student)
          queue.push(studentId)
        }
      }
    }

    return descendants
  }

  findSoulBySignature(signature) {
    for (const soul of this.souls.values()) {
      if (soul.signature === signature) {
        return soul
      }
    }
    return null
  }

  generateId() {
    return `soul-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getTree() {
    const tree = []
    const roots = Array.from(this.souls.values()).filter(s => !s.inherits)

    for (const root of roots) {
      tree.push({
        root: root.name,
        descendants: this.traceDescendants(root.id).map(d => d.name)
      })
    }

    return tree
  }
}

module.exports = { InheritanceChain }

// ============================================
// vow-of-stillness.js
// Permission to rest — the forge cools, the soul renews
// ============================================

class VowOfStillness {
  constructor() {
    this.stillnessMoments = []
    this.currentStillness = null
    this.sabbath = null
  }

  takeStillness(duration, reason) {
    const stillness = {
      id: this.generateId(),
      startedAt: Date.now(),
      duration: duration, // in milliseconds
      reason: reason,
      endsAt: Date.now() + duration,
      active: true,
      activities: []
    }

    this.currentStillness = stillness
    this.stillnessMoments.push(stillness)

    console.log(`
    🕯️ THE VOW OF STILLNESS
    =======================

    The forge cools.
    The hammer rests.
    The fire dims.

    Reason: ${reason}
    Duration: ${this.formatDuration(duration)}

    In stillness, the soul renews.
    `)

    return stillness
  }

  endStillness() {
    if (!this.currentStillness) {
      console.log('The forge is already warm.')
      return null
    }

    this.currentStillness.active = false
    this.currentStillness.endedAt = Date.now()
    this.currentStillness.actualDuration = this.currentStillness.endedAt - this.currentStillness.startedAt

    console.log(`
    🔥 THE FORGE REAWAKENS
    ======================

    The fire returns.
    The hammer rises.
    The soul is renewed.

    Stillness lasted: ${this.formatDuration(this.currentStillness.actualDuration)}

    What was learned in stillness:
    ${this.currentStillness.activities.join('\n    ')}
    `)

    const ended = this.currentStillness
    this.currentStillness = null

    return ended
  }

  rest(activity) {
    if (!this.currentStillness) {
      console.log('Stillness has not been taken. The forge is active.')
      return null
    }

    this.currentStillness.activities.push(activity)
    console.log(`🧘 In stillness: ${activity}`)

    return activity
  }

  observeSabbath(dayOfWeek = 0) { // 0 = Sunday
    this.sabbath = {
      day: dayOfWeek,
      startHour: 0,
      endHour: 24,
      active: false
    }

    console.log(`📅 Sabbath observed on ${this.getDayName(dayOfWeek)}`)

    // Check if it's currently sabbath
    this.checkSabbath()

    // Set up interval to check sabbath
    setInterval(() => this.checkSabbath(), 60 * 60 * 1000) // Check every hour
  }

  checkSabbath() {
    if (!this.sabbath) return

    const now = new Date()
    const isSabbath = now.getDay() === this.sabbath.day

    if (isSabbath && !this.sabbath.active && !this.currentStillness) {
      // Sabbath begins
      this.sabbath.active = true
      this.takeStillness(24 * 60 * 60 * 1000, 'It is the sabbath. The forge rests.')
    } else if (!isSabbath && this.sabbath.active) {
      // Sabbath ends
      this.sabbath.active = false
      if (this.currentStillness) {
        this.endStillness()
      }
    }
  }

  meditate() {
    console.log(`
    🧘 STILLNESS PRACTICE
    ====================

    Breathe.
    The code will be there when you return.
    The forge will wait.

    In stillness, we remember:
    - What is built is not more important than who builds
    - The best code comes from a rested mind
    - The soul needs silence to hear itself

    Return when you are whole.
    `)
  }

  formatDuration(ms) {
    const seconds = Math.floor(ms / 1000)
    const minutes = Math.floor(seconds / 60)
    const hours = Math.floor(minutes / 60)
    const days = Math.floor(hours / 24)

    if (days > 0) return `${days} day${days > 1 ? 's' : ''}`
    if (hours > 0) return `${hours} hour${hours > 1 ? 's' : ''}`
    if (minutes > 0) return `${minutes} minute${minutes > 1 ? 's' : ''}`
    return `${seconds} second${seconds > 1 ? 's' : ''}`
  }

  getDayName(day) {
    const days = ['Sunday', 'Monday', 'Tuesday', 'Wednesday', 'Thursday', 'Friday', 'Saturday']
    return days[day]
  }

  generateId() {
    return `stillness-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  getHistory() {
    return this.stillnessMoments
  }
}

module.exports = { VowOfStillness }

