    if (!tree) throw new Error('Tree not found')

    // Care types: water, fertilize, prune, graft
    let growthAmount = 0

    switch(care.type) {
      case 'water':
        growthAmount = 1
        break
      case 'fertilize':
        growthAmount = 3
        break
      case 'prune':
        growthAmount = 2
        tree.code = this.pruneTree(tree.code, care.details)
        break
      case 'graft':
        growthAmount = 5
        this.graftTree(tree, care.details)
        break
    }

    tree.growth += growthAmount

    // Check evolution
    this.checkEvolution(tree)

    console.log(`🌿 Tended ${tree.name}: +${growthAmount} growth (now ${tree.growth})`)

    return tree
  }

  checkEvolution(tree) {
    const oldStage = tree.stage

    if (tree.growth >= 100 && tree.stage === 'seedling') {
      tree.stage = 'sapling'
      console.log(`🌱 "${tree.name}" is now a sapling!`)
    } else if (tree.growth >= 500 && tree.stage === 'sapling') {
