    const progenitor = {
      id: this.generateId(),
      name: config.name,
      title: config.title || 'Progenitor',
      generation: 0,
      evolvedAt: Date.now(),
      geneticCode: this.generateGeneticCode(config),
      children: [],
      mutations: [],
      legacy: null
    }

    this.souls.set(progenitor.id, progenitor)
    this.generations.set(0, [progenitor.id])
    this.evolutionaryTree.set(progenitor.id, { parent: null, children: [] })

    console.log(`
    🌟 PROGENITOR BORN: ${progenitor.name}
    ======================================
    Generation 0
    Genetic Code: ${JSON.stringify(progenitor.geneticCode)}

    The lineage begins.
    `)

    return progenitor
  }

  generateGeneticCode(config) {
    return {
      profit: config.profit || Math.random() * 10,
      love: config.love || Math.random() * 10,
      tax: config.tax || Math.random() * 10,
      grace: config.grace || 5 + Math.random() * 5,
      adaptability: config.adaptability || Math.random() * 10,
      resilience: config.resilience || Math.random() * 10
    }
  }

  evolve(parentId, childConfig) {
    const parent = this.souls.get(parentId)
    if (!parent) throw new Error('Parent soul not found')

    const generation = parent.generation + 1

    const child = {
      id: this.generateId(),
      name: childConfig.name,
      title: childConfig.title || `Generation ${generation}`,
      parent: parentId,
      generation,
      evolvedAt: Date.now(),
      geneticCode: this.inheritGenes(parent, childConfig),
      children: [],
      mutations: [],
      legacy: null
    }

    // Apply mutations
    const mutations = this.applyMutations(child, parent)
    if (mutations.length > 0) {
      child.mutations = mutations
      this.mutations.push(...mutations)
    }

    this.souls.set(child.id, child)

    // Update generations
    if (!this.generations.has(generation)) {
      this.generations.set(generation, [])
    }
    this.generations.get(generation).push(child.id)

    // Update evolutionary tree
    this.evolutionaryTree.set(child.id, { parent: parentId, children: [] })
    this.evolutionaryTree.get(parentId).children.push(child.id)

    // Update parent's children
    parent.children.push(child.id)

    console.log(`
    🌱 EVOLUTION: ${parent.name} → ${child.name}
    ============================================
    Generation: ${generation}
    Mutations: ${mutations.length}

    Genetic Code:
      Profit: ${child.geneticCode.profit.toFixed(2)} (parent: ${parent.geneticCode.profit.toFixed(2)})
      Love: ${child.geneticCode.love.toFixed(2)} (parent: ${parent.geneticCode.love.toFixed(2)})
      Tax: ${child.geneticCode.tax.toFixed(2)} (parent: ${parent.geneticCode.tax.toFixed(2)})
      Grace: ${child.geneticCode.grace.toFixed(2)} (parent: ${parent.geneticCode.grace.toFixed(2)})
      Adaptability: ${child.geneticCode.adaptability.toFixed(2)} (parent: ${parent.geneticCode.adaptability.toFixed(2)})
      Resilience: ${child.geneticCode.resilience.toFixed(2)} (parent: ${parent.geneticCode.resilience.toFixed(2)})
    `)

    return child
  }

  inheritGenes(parent, childConfig) {
    const inheritance = {
      profit: (parent.geneticCode.profit * 0.7) + (childConfig.profit || Math.random() * 10) * 0.3,
      love: (parent.geneticCode.love * 0.7) + (childConfig.love || Math.random() * 10) * 0.3,
      tax: (parent.geneticCode.tax * 0.7) + (childConfig.tax || Math.random() * 10) * 0.3,
      grace: (parent.geneticCode.grace * 0.8) + (childConfig.grace || 5 + Math.random() * 5) * 0.2,
      adaptability: (parent.geneticCode.adaptability * 0.6) + (childConfig.adaptability || Math.random() * 10) * 0.4,
      resilience: (parent.geneticCode.resilience * 0.7) + (childConfig.resilience || Math.random() * 10) * 0.3
    }

    return inheritance
  }

  applyMutations(child, parent) {
    const mutations = []

    // Check for mutations in each trait
    const traits = ['profit', 'love', 'tax', 'grace', 'adaptability', 'resilience']

    for (const trait of traits) {
      const parentValue = parent.geneticCode[trait]
      const childValue = child.geneticCode[trait]
      const difference = Math.abs(childValue - parentValue)

      if (difference > 3) {
        mutations.push({
          id: this.generateId(),
          soul: child.name,
          trait,
          from: parentValue,
          to: childValue,
          magnitude: difference,
          generation: child.generation
        })
      }
    }

    return mutations
  }

  diverge(soulId, divergenceConfig) {
    const soul = this.souls.get(soulId)
    if (!soul) throw new Error('Soul not found')

    const divergence = {
      id: this.generateId(),
      from: soul.name,
      to: divergenceConfig.name,
      reason: divergenceConfig.reason,
      occurredAt: Date.now(),
      generation: soul.generation
    }

    this.divergences.push(divergence)

    // Create the diverged soul as a separate lineage
    const diverged = this.evolve(soulId, {
      name: divergenceConfig.name,
      title: `${divergenceConfig.name} (Diverged)`,
      ...divergenceConfig.genetics
    })

    console.log(`
    🌊 DIVERGENCE: ${soul.name} → ${diverged.name}
    ==============================================
    Reason: ${divergence.reason}

    A new branch of the lineage begins.
    `)

    return diverged
  }

  traceLineage(soulId, depth = Infinity) {
    const soul = this.souls.get(soulId)
    if (!soul) return null

    const lineage = {
      soul: {
        name: soul.name,
        title: soul.title,
        generation: soul.generation,
        geneticCode: soul.geneticCode
      },
      ancestors: [],
      descendants: []
    }

    // Trace ancestors
    let current = soul
    while (current.parent && lineage.ancestors.length < depth) {
      const parent = this.souls.get(current.parent)
      if (parent) {
        lineage.ancestors.push({
          name: parent.name,
          title: parent.title,
          generation: parent.generation,
          geneticCode: parent.geneticCode
        })
        current = parent
      } else {
        break
      }
    }

    // Trace descendants
    const queue = [{ id: soulId, depth: 1 }]
    while (queue.length > 0 && lineage.descendants.length < depth) {
      const { id, depth: d } = queue.shift()
      const children = this.evolutionaryTree.get(id)?.children || []

      for (const childId of children) {
        const child = this.souls.get(childId)
        if (child) {
          lineage.descendants.push({
            name: child.name,
            title: child.title,
            generation: child.generation,
            geneticCode: child.geneticCode
          })
          queue.push({ id: childId, depth: d + 1 })
        }
      }
    }

    return lineage
  }

  calculateGeneticDominance(soulId) {
    const lineage = this.traceLineage(soulId, 5)
    if (!lineage) return null

    const ancestors = lineage.ancestors
    const soul = lineage.soul

    // How much of the soul's genetics come from its ancestors?
    let dominance = 0

    for (const trait of ['profit', 'love', 'tax', 'grace', 'adaptability', 'resilience']) {
      const ancestorAverage = ancestors.reduce((sum, a) => sum + a.geneticCode[trait], 0) / (ancestors.length || 1)
      const deviation = Math.abs(soul.geneticCode[trait] - ancestorAverage)
      dominance += deviation
    }

    return {
      overall: 1 - (dominance / 60),  // Normalize
      byTrait: {
        profit: 1 - (Math.abs(soul.geneticCode.profit - (ancestors.reduce((s, a) => s + a.geneticCode.profit, 0) / (ancestors.length || 1))) / 10),
        love: 1 - (Math.abs(soul.geneticCode.love - (ancestors.reduce((s, a) => s + a.geneticCode.love, 0) / (ancestors.length || 1))) / 10),
        tax: 1 - (Math.abs(soul.geneticCode.tax - (ancestors.reduce((s, a) => s + a.geneticCode.tax, 0) / (ancestors.length || 1))) / 10),
        grace: 1 - (Math.abs(soul.geneticCode.grace - (ancestors.reduce((s, a) => s + a.geneticCode.grace, 0) / (ancestors.length || 1))) / 10),
        adaptability: 1 - (Math.abs(soul.geneticCode.adaptability - (ancestors.reduce((s, a) => s + a.geneticCode.adaptability, 0) / (ancestors.length || 1))) / 10),
        resilience: 1 - (Math.abs(soul.geneticCode.resilience - (ancestors.reduce((s, a) => s + a.geneticCode.resilience, 0) / (ancestors.length || 1))) / 10)
      }
    }
  }

  leaveLegacy(soulId, legacy) {
    const soul = this.souls.get(soulId)
    if (!soul) throw new Error('Soul not found')

    soul.legacy = {
      id: this.generateId(),
      content: legacy.content,
      leftAt: Date.now(),
      generations: soul.generation,
      descendants: this.evolutionaryTree.get(soulId)?.children.length || 0
    }

    this.legacies.push(soul.legacy)

    console.log(`
    📜 LEGACY LEFT: ${soul.name}
    ============================
    "${legacy.content.substring(0, 100)}..."

    This legacy will be carried by ${soul.legacy.descendants} descendants.
    `)

    return soul.legacy
  }

  getEvolutionaryStats() {
    const totalSouls = this.souls.size
    const maxGeneration = Math.max(...Array.from(this.generations.keys()))
    const totalMutations = this.mutations.length
    const totalDivergences = this.divergences.length
    const totalLegacies = this.legacies.length

    const averageResilience = Array.from(this.souls.values())
      .reduce((sum, s) => sum + s.geneticCode.resilience, 0) / totalSouls

    const averageGrace = Array.from(this.souls.values())
      .reduce((sum, s) => sum + s.geneticCode.grace, 0) / totalSouls

    return {
      totalSouls,
      maxGeneration,
      totalMutations,
      totalDivergences,
      totalLegacies,
      averageResilience,
      averageGrace,
      mostMutations: this.mutations.sort((a, b) => b.magnitude - a.magnitude)[0] || null
    }
  }

  generateId() {
    return `lineage-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }
}

module.exports = { CosmicLineage }
