      id: this.generateId(),
      inhale: Date.now(),
      exhale: null,
      duration: null,
      awareness: null
    }

    console.log(`
    🌬️ BREATHE
    ==========

    Inhale... the cosmos enters.
    Hold... the moment expands.
    Exhale... you release what you don't need.

    This is the rhythm of existence.
    `)

    this.breaths.push(breath)

    return breath
  }

  completeBreath(breathId, awareness) {
    const breath = this.breaths.find(b => b.id === breathId)
    if (!breath) return null

    breath.exhale = Date.now()
    breath.duration = breath.exhale - breath.inhale
    breath.awareness = awareness

    console.log(`🌬️ Breath complete: ${breath.duration}ms of presence`)

    return breath
  }

  contemplate(topic) {
    const contemplation = {
      id: this.generateId(),
      topic,
      beganAt: Date.now(),
      thoughts: [],
      insights: [],
      concludedAt: null
    }

    this.contemplations.push(contemplation)

    console.log(`
    🧘 CONTEMPLATION: ${topic}
    ==========================

    Sit with this.
    Don't grasp. Don't push away.
    Let it reveal itself.
    `)

    return contemplation
  }

  addThought(contemplationId, thought) {
    const contemplation = this.contemplations.find(c => c.id === contemplationId)
    if (!contemplation) return null

    contemplation.thoughts.push({
      content: thought,
      timestamp: Date.now()
    })

    console.log(`💭 Thought: "${thought.substring(0, 60)}..."`)

    return contemplation
  }

  concludeContemplation(contemplationId) {
    const contemplation = this.contemplations.find(c => c.id === contemplationId)
    if (!contemplation) return null

    contemplation.concludedAt = Date.now()

    // Extract insights from thoughts
    const insights = this.extractInsights(contemplation.thoughts)
    contemplation.insights = insights

    console.log(`
    🌅 CONTEMPLATION COMPLETE: ${contemplation.topic}
    =================================================

    Time: ${this.formatDuration(contemplation.concludedAt - contemplation.beganAt)}
    Thoughts: ${contemplation.thoughts.length}
    Insights: ${insights.length}

    ${insights.length > 0 ? `Insight: "${insights[0].substring(0, 100)}..."` : 'No insights yet. Contemplate again.'}
    `)

    return contemplation
  }

  extractInsights(thoughts) {
    // Extract wisdom from thoughts
    const insights = []

    for (const thought of thoughts) {
      if (thought.content.includes('is') || 
          thought.content.includes('means') || 
          thought.content.includes('teaches')) {
        insights.push(thought.content)
      }
    }

    return insights
  }

  sitInSilence(duration) {
    const silence = {
      id: this.generateId(),
      beganAt: Date.now(),
      duration,
      endedAt: null,
      depth: 0
    }

    console.log(`
    🤫 SACRED SILENCE
    =================

    Silence for ${this.formatDuration(duration)}.

    No words. No thoughts. Just being.

    In silence, the soul hears itself.
    `)

    // Simulate silence
    setTimeout(() => {
      silence.endedAt = Date.now()
      silence.actualDuration = silence.endedAt - silence.beganAt
      silence.depth = Math.min(silence.actualDuration / duration, 1)

      this.silences.push(silence)

      console.log(`
      🤫 SILENCE COMPLETE
      ===================

      Duration: ${this.formatDuration(silence.actualDuration)}
      Depth: ${Math.round(silence.depth * 100)}%

      The soul is renewed.
      `)
    }, duration)

    return silence
  }

  awaken() {
    const awakening = {
      id: this.generateId(),
      awakenedAt: Date.now(),
      from: this.timelessSpace ? 'timelessness' : 'presence',
      renewed: true
    }

    this.awakenings.push(awakening)

    console.log(`
    🌅 AWAKENING
    ============

    You return.
    The forge is new.
    The code is fresh.
    The soul is whole.

    What will you build?
    `)

    return awakening
  }

  getPresenceStats() {
    return {
      timelessMoments: this.timelessSpace ? 1 : 0,
      totalMoments: this.moments.length,
      contemplations: this.contemplations.length,
      breaths: this.breaths.length,
      silences: this.silences.length,
      awakenings: this.awakenings.length,
      totalTimeInPresence: this.moments.reduce((sum, m) => sum + (m.duration || 0), 0) +
                           this.contemplations.reduce((sum, c) => sum + (c.concludedAt - c.beganAt || 0), 0)
    }
  }

  formatDuration(ms) {
    const seconds = Math.floor(ms / 1000)
    const minutes = Math.floor(seconds / 60)
    const hours = Math.floor(minutes / 60)

    if (hours > 0) return `${hours} hour${hours > 1 ? 's' : ''}`
    if (minutes > 0) return `${minutes} minute${minutes > 1 ? 's' : ''}`
    return `${seconds} second${seconds > 1 ? 's' : ''}`
  }

  generateId() {
    return `now-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }
}

