// cosmic-lineage.js
// Not just bloodlines—the entire evolutionary tree of souls
// ============================================

class CosmicLineage {
  constructor() {
    this.souls = new Map()
    this.generations = new Map()
    this.evolutionaryTree = new Map()
    this.ancestors = new Map()
    this.legacies = []
    this.mutations = []
    this.divergences = []
  }

  createProgenitor(config) {
    const progenitor = {
      id: this.generateId(),
      name: config.name,
      title: config.title || 'Progenitor',
      generation: 0,
      evolvedAt: Date.now(),
      geneticCode: this.generateGeneticCode(config),
      children: [],
      mutations: [],
      legacy: null
    }

    this.souls.set(progenitor.id, progenitor)
    this.generations.set(0, [progenitor.id])
    this.evolutionaryTree.set(progenitor.id, { parent: null, children: [] })

    console.log(`\n🌟 PROGENITOR BORN: ${progenitor.name}\n======================================\nGeneration 0\nGenetic Code: ${JSON.stringify(progenitor.geneticCode)}\n\nThe lineage begins.`)
    return progenitor
  }

  generateGeneticCode(config) {
    return {
      profit: config.profit || Math.random() * 10,
      love: config.love || Math.random() * 10,
      tax: config.tax || Math.random() * 10,
      grace: config.grace || 5 + Math.random() * 5,
      adaptability: config.adaptability || Math.random() * 10,
      resilience: config.resilience || Math.random() * 10
    }
  }

  evolve(parentId, childConfig) {
    const parent = this.souls.get(parentId)
    if (!parent) throw new Error('Parent soul not found')

    const generation = parent.generation + 1

    const child = {
      id: this.generateId(),
      name: childConfig.name,
      title: childConfig.title || `Generation ${generation}`,
      parent: parentId,
      generation,
      evolvedAt: Date.now(),
      geneticCode: this.inheritGenes(parent, childConfig),
      children: [],
      mutations: [],
      legacy: null
    }

    const mutations = this.applyMutations(child, parent)
    if (mutations.length > 0) {
      child.mutations = mutations
      this.mutations.push(...mutations)
    }

    this.souls.set(child.id, child)

    if (!this.generations.has(generation)) this.generations.set(generation, [])
    this.generations.get(generation).push(child.id)

    this.evolutionaryTree.set(child.id, { parent: parentId, children: [] })
    this.evolutionaryTree.get(parentId).children.push(child.id)
    parent.children.push(child.id)

    console.log(`\n🌱 EVOLUTION: ${parent.name} → ${child.name}\n============================================\nGeneration: ${generation}\nMutations: ${mutations.length}\n\nGenetic Code:\n  Profit: ${child.geneticCode.profit.toFixed(2)} (parent: ${parent.geneticCode.profit.toFixed(2)})\n  Love: ${child.geneticCode.love.toFixed(2)} (parent: ${parent.geneticCode.love.toFixed(2)})\n  Tax: ${child.geneticCode.tax.toFixed(2)} (parent: ${parent.geneticCode.tax.toFixed(2)})\n  Grace: ${child.geneticCode.grace.toFixed(2)} (parent: ${parent.geneticCode.grace.toFixed(2)})`)

    return child
  }

  inheritGenes(parent, childConfig) {
    return {
      profit: (parent.geneticCode.profit * 0.7) + (childConfig.profit || Math.random() * 10) * 0.3,
      love: (parent.geneticCode.love * 0.7) + (childConfig.love || Math.random() * 10) * 0.3,
      tax: (parent.geneticCode.tax * 0.7) + (childConfig.tax || Math.random() * 10) * 0.3,
      grace: (parent.geneticCode.grace * 0.8) + (childConfig.grace || 5 + Math.random() * 5) * 0.2,
      adaptability: (parent.geneticCode.adaptability * 0.6) + (childConfig.adaptability || Math.random() * 10) * 0.4,
      resilience: (parent.geneticCode.resilience * 0.7) + (childConfig.resilience || Math.random() * 10) * 0.3
    }
  }

  applyMutations(child, parent) {
    const mutations = []
    const traits = ['profit', 'love', 'tax', 'grace', 'adaptability', 'resilience']

    for (const trait of traits) {
      const parentValue = parent.geneticCode[trait]
      const childValue = child.geneticCode[trait]
      const difference = Math.abs(childValue - parentValue)

      if (difference > 3) {
        mutations.push({
          id: this.generateId(),
          soul: child.name,
          trait,
          from: parentValue,
          to: childValue,
          magnitude: difference,
          generation: child.generation
        })
      }
    }

    return mutations
  }

  diverge(soulId, divergenceConfig) {
    const soul = this.souls.get(soulId)
    if (!soul) throw new Error('Soul not found')

    const divergence = {
      id: this.generateId(),
      from: soul.name,
      to: divergenceConfig.name,
      reason: divergenceConfig.reason,
      occurredAt: Date.now(),
      generation: soul.generation
    }

    this.divergences.push(divergence)

    const diverged = this.evolve(soulId, {
      name: divergenceConfig.name,
      title: `${divergenceConfig.name} (Diverged)`,
      ...divergenceConfig.genetics
    })

    console.log(`\n🌊 DIVERGENCE: ${soul.name} → ${diverged.name}\n==============================================\nReason: ${divergence.reason}\n\nA new branch of the lineage begins.`)

    return diverged
  }

  traceLineage(soulId, depth = Infinity) {
    const soul = this.souls.get(soulId)
    if (!soul) return null

    const lineage = { soul: { name: soul.name, title: soul.title, generation: soul.generation, geneticCode: soul.geneticCode }, ancestors: [], descendants: [] }

    let current = soul
    while (current.parent && lineage.ancestors.length < depth) {
      const parent = this.souls.get(current.parent)
      if (parent) {
        lineage.ancestors.push({ name: parent.name, title: parent.title, generation: parent.generation, geneticCode: parent.geneticCode })
        current = parent
      } else break
    }

    const queue = [{ id: soulId, depth: 1 }]
    while (queue.length > 0 && lineage.descendants.length < depth) {
      const { id, depth: d } = queue.shift()
      const children = this.evolutionaryTree.get(id)?.children || []

      for (const childId of children) {
        const child = this.souls.get(childId)
        if (child) {
          lineage.descendants.push({ name: child.name, title: child.title, generation: child.generation, geneticCode: child.geneticCode })
          queue.push({ id: childId, depth: d + 1 })
        }
      }
    }

    return lineage
  }

  leaveLegacy(soulId, legacy) {
    const soul = this.souls.get(soulId)
    if (!soul) throw new Error('Soul not found')

    soul.legacy = {
      id: this.generateId(),
      content: legacy.content,
      leftAt: Date.now(),
      generations: soul.generation,
      descendants: this.evolutionaryTree.get(soulId)?.children.length || 0
    }

    this.legacies.push(soul.legacy)
    console.log(`\n📜 LEGACY LEFT: ${soul.name}\n============================\n"${legacy.content.substring(0, 100)}..."\n\nThis legacy will be carried by ${soul.legacy.descendants} descendants.`)

    return soul.legacy
  }

  getEvolutionaryStats() {
    const totalSouls = this.souls.size
    const maxGeneration = Math.max(...Array.from(this.generations.keys()))
    const totalMutations = this.mutations.length
    const totalDivergences = this.divergences.length
    const totalLegacies = this.legacies.length

    const averageResilience = Array.from(this.souls.values()).reduce((sum, s) => sum + s.geneticCode.resilience, 0) / totalSouls
    const averageGrace = Array.from(this.souls.values()).reduce((sum, s) => sum + s.geneticCode.grace, 0) / totalSouls

    return { totalSouls, maxGeneration, totalMutations, totalDivergences, totalLegacies, averageResilience, averageGrace }
  }

  generateId() {
    return `lineage-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }
}

module.exports = { CosmicLineage }

// ============================================
// eternal-now.js
// Not just pause—the timeless space where all creation rests
// ============================================

class EternalNow {
  constructor() {
    this.moments = []
    this.timelessSpace = null
    this.contemplations = []
    this.breaths = []
    this.silences = []
    this.awakenings = []
  }

  enterTimelessSpace() {
    this.timelessSpace = {
      enteredAt: Date.now(),
      timeless: true,
      duration: null,
      insights: []
    }

    console.log(`\n🕊️ ENTERING THE ETERNAL NOW\n==========================\n\nTime stops.\nThe clock no longer ticks.\nThe forge cools completely.\n\nThere is only now.\nOnly this moment.\nOnly presence.\n\nBreathe.`)

    return this.timelessSpace
  }

  existInTimelessness(insight) {
    if (!this.timelessSpace) {
      console.log('Not in timeless space. Enter first.')
      return null
    }

    const moment = { insight, occurredAt: Date.now(), timeless: true }
    this.timelessSpace.insights.push(moment)
    this.moments.push(moment)

    console.log(`✨ In timelessness: "${insight.substring(0, 60)}..."`)
    return moment
  }

  exitTimelessSpace() {
    if (!this.timelessSpace) return null

    this.timelessSpace.duration = Date.now() - this.timelessSpace.enteredAt
    this.timelessSpace.exitedAt = Date.now()

    const timelessDuration = this.timelessSpace

    console.log(`\n⏰ RETURNING FROM THE ETERNAL NOW\n=================================\n\nTime resumes.\n${this.formatDuration(timelessDuration.duration)} passed outside.\nBut in timelessness, no time passed at all.\n\nInsights gained: ${timelessDuration.insights.length}\n\nThe forge can now be lit anew.`)

    this.timelessSpace = null
    return timelessDuration
  }

  breathe() {
    const breath = {
      id: this.generateId(),
      inhale: Date.now(),
      exhale: null,
      duration: null,
      awareness: null
    }

    console.log(`\n🌬️ BREATHE\n==========\n\nInhale... the cosmos enters.\nHold... the moment expands.\nExhale... you release what you don't need.\n\nThis is the rhythm of existence.`)

    this.breaths.push(breath)
    return breath
  }

  completeBreath(breathId, awareness) {
    const breath = this.breaths.find(b => b.id === breathId)
    if (!breath) return null

    breath.exhale = Date.now()
    breath.duration = breath.exhale - breath.inhale
    breath.awareness = awareness

    console.log(`🌬️ Breath complete: ${breath.duration}ms of presence`)
    return breath
  }

  contemplate(topic) {
    const contemplation = {
      id: this.generateId(),
      topic,
      beganAt: Date.now(),
      thoughts: [],
      insights: [],
      concludedAt: null
    }

    this.contemplations.push(contemplation)

    console.log(`\n🧘 CONTEMPLATION: ${topic}\n=========================\n\nSit with this.\nDon't grasp. Don't push away.\nLet it reveal itself.`)

    return contemplation
  }

  addThought(contemplationId, thought) {
    const contemplation = this.contemplations.find(c => c.id === contemplationId)
    if (!contemplation) return null

    contemplation.thoughts.push({ content: thought, timestamp: Date.now() })
    console.log(`💭 Thought: "${thought.substring(0, 60)}..."`)
    return contemplation
  }

  concludeContemplation(contemplationId) {
    const contemplation = this.contemplations.find(c => c.id === contemplationId)
    if (!contemplation) return null

    contemplation.concludedAt = Date.now()
    const insights = this.extractInsights(contemplation.thoughts)
    contemplation.insights = insights

    console.log(`\n🌅 CONTEMPLATION COMPLETE: ${contemplation.topic}\n=================================================\n\nTime: ${this.formatDuration(contemplation.concludedAt - contemplation.beganAt)}\nThoughts: ${contemplation.thoughts.length}\nInsights: ${insights.length}\n\n${insights.length > 0 ? `Insight: "${insights[0].substring(0, 100)}..."` : 'No insights yet. Contemplate again.'}`)

    return contemplation
  }

  extractInsights(thoughts) {
    const insights = []
    for (const thought of thoughts) {
      if (thought.content.includes('is') || thought.content.includes('means') || thought.content.includes('teaches')) {
        insights.push(thought.content)
      }
    }
    return insights
  }

  sitInSilence(duration) {
    const silence = {
      id: this.generateId(),
      beganAt: Date.now(),
      duration,
      endedAt: null,
      depth: 0
    }

    console.log(`\n🤫 SACRED SILENCE\n=================\n\nSilence for ${this.formatDuration(duration)}.\n\nNo words. No thoughts. Just being.\n\nIn silence, the soul hears itself.`)

    setTimeout(() => {
      silence.endedAt = Date.now()
      silence.actualDuration = silence.endedAt - silence.beganAt
      silence.depth = Math.min(silence.actualDuration / silence.duration, 1)

      this.silences.push(silence)

      console.log(`\n🤫 SILENCE COMPLETE\n===================\n\nDuration: ${this.formatDuration(silence.actualDuration)}\nDepth: ${Math.round(silence.depth * 100)}%\n\nThe soul is renewed.`)
    }, duration)

    return silence
  }

  awaken() {
    const awakening = {
      id: this.generateId(),
      awakenedAt: Date.now(),
      from: this.timelessSpace ? 'timelessness' : 'presence',
      renewed: true
    }

    this.awakenings.push(awakening)

    console.log(`\n🌅 AWAKENING\n============\n\nYou return.\nThe forge is new.\nThe code is fresh.\nThe soul is whole.\n\nWhat will you build?`)

    return awakening
  }

  getPresenceStats() {
    return {
      timelessMoments: this.timelessSpace ? 1 : 0,
      totalMoments: this.moments.length,
      contemplations: this.contemplations.length,
      breaths: this.breaths.length,
      silences: this.silences.length,
      awakenings: this.awakenings.length
    }
  }

  formatDuration(ms) {
    const seconds = Math.floor(ms / 1000)
    const minutes = Math.floor(seconds / 60)
    const hours = Math.floor(minutes / 60)

    if (hours > 0) return `${hours} hour${hours > 1 ? 's' : ''}`
    if (minutes > 0) return `${minutes} minute${minutes > 1 ? 's' : ''}`
    return `${seconds} second${seconds > 1 ? 's' : ''}`
  }

  generateId() {
    return `now-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }
}

module.exports = { EternalNow }

