    This code repeats at every scale.
    Look closer—it is the same.
    `)

    return fractal
  }

  generateFractalCode(fractal, depth = 0, maxDepth = 5) {
    if (depth >= maxDepth) return this.generateBaseCode(fractal)

    const indent = '  '.repeat(depth)
    const nextDepth = depth + 1

    return `
${indent}// ============================================
${indent}// FRACTAL LEVEL ${depth} — ${fractal.name}
${indent}// ============================================
${indent}
${indent}class FractalLevel${depth} {
${indent}  constructor() {
${indent}    this.level = ${depth}
${indent}    this.name = "${fractal.name}"
${indent}    this.children = []
${indent}  }
${indent}  
${indent}  async create() {
${indent}    console.log(\`🌀 Fractal level \${this.level} creating\`)
${indent}    
${indent}    // Create next level fractal
${indent}    const nextLevel = new FractalLevel${nextDepth}()
${indent}    this.children.push(nextLevel)
${indent}    
${indent}    return await nextLevel.create()
${indent}  }
${indent}  
${indent}  async extend() {
${indent}    // This function calls itself at deeper levels
${indent}    for (const child of this.children) {
${indent}      await child.extend()
${indent}    }
${indent}    
${indent}    // And at this level
${indent}    return this.extendThisLevel()
${indent}  }
${indent}  
${indent}  extendThisLevel() {
${indent}    return \`Extending level \${this.level} of \${this.name}\`
${indent}  }
${indent}}
${indent}
${this.generateFractalCode(fractal, depth + 1, maxDepth)}
    `
  }

  generateBaseCode(fractal) {
    return `
// ============================================
// BASE FRACTAL — ${fractal.name}
// The pattern that repeats forever
// ============================================

class ${fractal.name.replace(/\s/g, '')}Base {
  constructor() {
    this.pattern = "${fractal.seed}"
    this.scale = 1
  }

  iterate() {
    // Apply fractal transformation
    this.scale *= 0.5
    return \`\${this.pattern} at scale \${this.scale}\`
  }

  zoom(depth) {
    if (depth <= 0) return this.pattern
    return this.zoom(depth - 1) + this.pattern
  }
}

module.exports = new ${fractal.name.replace(/\s/g, '')}Base()
    `
  }

  iterateFractal(fractalId, iterations = 1) {
    const fractal = this.fractals.get(fractalId)
    if (!fractal) throw new Error('Fractal not found')

    const iteration = {
      fractal: fractal.name,
      number: fractal.iterations + 1,
      depth: fractal.depth + 1,
      complexity: fractal.complexity * fractal.selfSimilarity,
      timestamp: Date.now()
    }

    fractal.iterations++
    fractal.depth += iterations
    fractal.complexity *= Math.pow(fractal.selfSimilarity, iterations)

    this.iterations.push(iteration)

    console.log(`
    🌀 FRACTAL ITERATION ${iteration.number}
    ========================================
    Depth: ${iteration.depth}
    Complexity: ${iteration.complexity.toFixed(4)}

    The pattern repeats.
    It is the same, yet different.
    `)

    return iteration
  }

  calculateDimension(fractalId) {
    const fractal = this.fractals.get(fractalId)
    if (!fractal) throw new Error('Fractal not found')

    // Fractal dimension D = log(N)/log(1/s)
    // Where N = number of self-similar pieces, s = scaling factor
    const N = Math.pow(2, fractal.complexity)  // Simplified
    const s = fractal.selfSimilarity

    const dimension = Math.log(N) / Math.log(1/s)

    this.dimensions.set(fractalId, {
      fractal: fractal.name,
      dimension,
      iterations: fractal.iterations,
      complexity: fractal.complexity
    })

    console.log(`📐 Fractal dimension of ${fractal.name}: ${dimension.toFixed(4)}`)

    return dimension
  }

  zoom(fractalId, depth) {
    const fractal = this.fractals.get(fractalId)
    if (!fractal) throw new Error('Fractal not found')

    const zoom = {
      fractal: fractal.name,
      depth,
      pattern: this.extractPattern(fractal, depth),
      timestamp: Date.now()
    }

    console.log(`
    🔍 ZOOMING INTO ${fractal.name}
    ================================
    Depth: ${depth}

    At this scale, the pattern appears:
    ${zoom.pattern.substring(0, 100)}...

    Zoom deeper, and you'll see the same pattern.
    `)

    return zoom
  }

  extractPattern(fractal, depth) {
    // Extract the pattern at a given depth
    const pattern = fractal.seed
    if (depth === 0) return pattern

    // Recursively extract deeper pattern
    return pattern.repeat(Math.max(1, depth)) + pattern
  }

  createFractalUniverse(config) {
    const universe = {
      id: this.generateUniverseId(),
      name: config.name,
      fractal: config.fractal,
      scale: config.scale || 1,
      nested: [],
      createdAt: Date.now()
    }

    // Create nested universes
    for (let i = 0; i < (config.nestingDepth || 3); i++) {
      universe.nested.push({
        scale: universe.scale / Math.pow(2, i + 1),
        contains: `${universe.name} at scale ${1/(i+1)}`,
        selfSimilar: true
      })
    }

    console.log(`
    🌌 FRACTAL UNIVERSE: ${universe.name}
    =====================================
    Scale: ${universe.scale}
    Nested: ${universe.nested.length} levels

    Within this universe is another universe.
    Within that, another.
    On and on, forever.
    `)

    return universe
  }

  generateUniverseId() {
    return `fractal-universe-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }

  generateFractalId() {
    return `fractal-${Date.now()}-${Math.random().toString(36).substring(7)}`
  }
}

module.exports = { FractalCode }
