      strength: resonanceStrength,
      frequency: (soul1.frequency + soul2.frequency) / 2,
      created: Date.now()
    }

    soul1.resonance.push(resonance.id)
    soul2.resonance.push(resonance.id)
    this.resonances.push(resonance)

    console.log(`
